// Build a compact text summary of all competitor profiles to feed the
// synthesis LLM. Keeps the prompt focused and avoids passing huge JSON.
const input = $input.first().json;

const target = input.target_company ?? 'the target company';
const industry = input.inferred_industry ?? '';
const focus = input.focus_area ?? '';
const competitors = Array.isArray(input.competitors) ? input.competitors : [];

let block = `Target company: ${target}\nIndustry: ${industry}\nFocus area: ${focus || 'none specified'}\n\nCOMPETITORS:\n`;

for (const c of competitors) {
  block += `\n--- ${c.name} (threat: ${c.threat_level ?? 'n/a'}) ---\n`;
  block += `Pricing: ${c.pricing ?? 'n/a'}\n`;
  const feats = Array.isArray(c.key_features) ? c.key_features.join('; ') : (c.key_features ?? '');
  block += `Key features: ${feats}\n`;
  block += `Positioning: ${c.positioning ?? ''}\n`;
  const news = Array.isArray(c.recent_news) ? c.recent_news.join('; ') : (c.recent_news ?? '');
  block += `Recent news: ${news}\n`;
  block += `Digital/ecommerce presence: ${c.digital_presence ?? 'n/a'}\n`;
}

return [{
  json: {
    target_company: target,
    inferred_industry: industry,
    focus_area: focus,
    competitors: competitors,
    competitor_brief: block
  }
}];

// Parse the synthesis JSON and merge it with the competitor data into one
// complete briefing object to return to the caller (and ultimately Streamlit).
const item = $input.first();
let raw = item.json.output ?? item.json.text ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw);

raw = raw.replace(/```(?:json)?/gi, '').trim();
const firstBrace = raw.indexOf('{');
const lastBrace = raw.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  raw = raw.slice(firstBrace, lastBrace + 1);
}
raw = raw.replace(/,\s*([}\]])/g, '$1');

// Pull the upstream competitor data + context from the Build Competitor Brief node.
let ctx = {};
try {
  ctx = $('Build Competitor Brief').first().json;
} catch (e) { ctx = {}; }

let synth;
try {
  synth = JSON.parse(raw);
} catch (err) {
  synth = {
    summary: 'Synthesis parse error.',
    competitor_strengths: [],
    gaps_and_recommendations: [],
    _parse_error: err.message,
    _raw_output: item.json.output ?? item.json.text ?? ''
  };
}

// Assemble the final briefing.
return [{
  json: {
    target_company: ctx.target_company ?? '',
    inferred_industry: ctx.inferred_industry ?? '',
    focus_area: ctx.focus_area ?? '',
    competitors: ctx.competitors ?? [],
    summary: synth.summary ?? '',
    competitor_strengths: synth.competitor_strengths ?? [],
    gaps_and_recommendations: synth.gaps_and_recommendations ?? [],
    digital_gaps: synth.digital_gaps ?? [],
    feature_scores: synth.feature_scores || [],
    generated_at: new Date().toISOString(),
    parse_error: synth._parse_error ?? ''
  }
}];
